(()=>{
'use strict';
const $=s=>document.querySelector(s);
let modal,fill,title,detail,pct,note,hideTimer;
function css(){if($('#adminProgressPopupCss'))return;const s=document.createElement('style');s.id='adminProgressPopupCss';s.textContent=`.adminPopMask{position:fixed;inset:0;z-index:99999;background:rgba(15,23,42,.58);backdrop-filter:blur(8px);display:none;place-items:center;padding:18px}.adminPopMask.on{display:grid}.adminPop{width:min(430px,100%);background:#fff;border-radius:22px;border:1px solid #d1fae5;box-shadow:0 28px 100px rgba(2,6,23,.28);padding:20px;color:#111827;text-align:center}.adminPopIcon{width:62px;height:62px;border-radius:20px;margin:0 auto 12px;display:grid;place-items:center;background:linear-gradient(135deg,#087b34,#22c55e);color:#fff;font-weight:950;font-size:28px}.adminPop h3{margin:0;font-size:20px;letter-spacing:-.03em;color:#064e3b}.adminPop p{margin:8px 0 14px;color:#4b5563;line-height:1.45;word-break:break-word}.adminPopHead{display:flex;align-items:center;justify-content:space-between;font-size:12px;font-weight:950;color:#087b34;margin-bottom:7px}.adminPopTrack{height:14px;border-radius:999px;background:#e5e7eb;overflow:hidden;border:1px solid #d1d5db}.adminPopFill{height:100%;width:0;background:linear-gradient(90deg,#087b34,#22c55e);transition:.18s ease}.adminPopNote{margin-top:10px;font-size:12px;color:#6b7280;line-height:1.45}.adminLatestBadge{margin-top:10px;display:inline-block;border-radius:999px;padding:7px 11px;background:#dcfce7;color:#166534;font-size:12px;font-weight:950;border:1px solid #bbf7d0}`;document.head.appendChild(s)}
function ensure(){css();if(modal)return;modal=document.createElement('div');modal.className='adminPopMask';modal.innerHTML=`<div class="adminPop"><div class="adminPopIcon">⇧</div><h3 id="adminPopTitle">กำลังทำงาน</h3><p id="adminPopDetail">รอสถานะ</p><div class="adminPopHead"><span>สถานะจริงจากแถบหลัก</span><b id="adminPopPct">0%</b></div><div class="adminPopTrack"><div class="adminPopFill" id="adminPopFill"></div></div><div class="adminPopNote" id="adminPopNote">อ่านสถานะจริง ไม่กดตั้ง active อัตโนมัติ</div></div>`;document.body.appendChild(modal);fill=$('#adminPopFill');title=$('#adminPopTitle');detail=$('#adminPopDetail');pct=$('#adminPopPct');note=$('#adminPopNote')}
function percentFromBar(){const w=($('#bar')&&$('#bar').style&&$('#bar').style.width)||'';const m=w.match(/([0-9.]+)/);return m?Math.max(0,Math.min(100,Number(m[1])||0)):0}
function statusText(fallback=''){return String($('#status')?.textContent||fallback||'กำลังทำงาน').trim()}
function show(msg){ensure();clearTimeout(hideTimer);const n=Math.round(percentFromBar()),text=statusText(msg);modal.classList.add('on');fill.style.width=n+'%';pct.textContent=n+'%';detail.textContent=text;if(/ผิดพลาด|error|ไม่ได้|fail/i.test(text)){title.textContent='อัปโหลดหรือแปลงไฟล์ไม่สำเร็จ';note.textContent='สถานะผิดพลาดจากแถบหลัก'}else if(n>=100||/เสร็จ|สำเร็จ|active|ล่าสุด|พร้อมใช้งาน/i.test(text)){title.textContent='อัปโหลด/แปลงไฟล์สำเร็จ';note.textContent='เสร็จตามสถานะหลักแล้ว ไม่มีการกดปุ่ม active ซ้ำ';hideTimer=setTimeout(()=>modal.classList.remove('on'),1800)}else if(/อ่าน|แปลง|index|JSON/i.test(text)){title.textContent='กำลังแปลงไฟล์ DOIT';note.textContent='อ่านเปอร์เซ็นต์จากหลอดสถานะหลักเท่านั้น'}else if(/อัปโหลด|Cloud/i.test(text)){title.textContent='กำลังอัปโหลดขึ้น Cloud';note.textContent='อ่านเปอร์เซ็นต์จากหลอดสถานะหลักเท่านั้น'}else{title.textContent='กำลังทำงาน';note.textContent='ไม่สร้างเลขหลอกและไม่กดปุ่มแทนผู้ใช้'}}
function refresh(){show()}
function markLatest(){const el=$('#cloudStatus');if(!el)return;const tx=el.textContent||'';if(/ตั้งเป็นไฟล์ล่าสุดแล้ว|Cloud JSON active|อัปโหลด Excel \+ JSON และตั้งเป็นไฟล์ล่าสุดแล้ว/.test(tx)){try{localStorage.setItem('doit-admin-latest-status',tx);localStorage.setItem('doit-admin-latest-at',new Date().toISOString())}catch{}show('ตั้งไฟล์ล่าสุดสำเร็จ');if(!$('#adminLatestBadge')){const b=document.createElement('div');b.id='adminLatestBadge';b.className='adminLatestBadge';b.textContent='ไฟล์ล่าสุดถูกตั้งแล้ว';el.appendChild(b)}}}
function bind(){ensure();['bar','pct','status'].forEach(id=>{const el=$('#'+id);if(el)new MutationObserver(refresh).observe(el,{attributes:true,childList:true,subtree:true,characterData:true,attributeFilter:['style']})});const cs=$('#cloudStatus');if(cs)new MutationObserver(markLatest).observe(cs,{childList:true,subtree:true,characterData:true});const file=$('#file');if(file)file.addEventListener('change',()=>{const f=file.files&&file.files[0];if(f)show('เลือกไฟล์: '+f.name)},true);const up=$('#uploadCloud');if(up)up.addEventListener('click',()=>show('เริ่มอัปโหลดขึ้น Cloud'),true);setTimeout(markLatest,600)}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',bind);else bind();
})();
